import ast

# Read layer4.py
with open\('cynic/protocol/lnsp/layer4.py', 'r'\) as f:
    content = f.read\(\)

tree = ast.parse\(content\)

missing_docs = []

for node in ast.walk\(tree\):
    if isinstance\(node, ast.ClassDef\):
        if ast.get_docstring\(node\) is None:
            missing_docs.append\(f"Class {node.name} at line {node.lineno}"\)
    elif isinstance\(node, \(ast.FunctionDef, ast.AsyncFunctionDef\)\):
        if node.name not in ['__init__', '__post_init__', '__str__', '__repr__']:
            if ast.get_docstring\(node\) is None:
                missing_docs.append\(f"Method {node.name} at line {node.lineno}"\)

if missing_docs:
    print\("Missing Docstrings:"\)
    for item in missing_docs:
        print\(f"  {item}"\)
else:
    print\("All classes and methods have docstrings"\)
EOF)
